const c=100;export function collectPipelineHooks(i,t){const o=[];for(const e of i.values()){if(!e.active)continue;const r=e.extension.pipelineHooks;if(!r)continue;const n=r[t];n&&o.push({extensionName:e.id,phase:t,fn:n,priority:100})}return o.sort((e,r)=>e.priority-r.priority),o}export function collectActiveProcessors(i){const t=[];for(const o of i.values()){if(!o.active)continue;const e=o.extension.narrativeProcessors;if(e)for(const r of e)t.push({...r,extensionName:o.id})}return t.sort((o,e)=>o.priority-e.priority),t}export async function executePipelineHooks(i,t,o,e){let r=t;for(const n of i)try{r=await n.fn(r,o)}catch(s){e.error(`Hook from "${n.extensionName}" on phase "${n.phase}" threw: ${s instanceof Error?s.message:String(s)}`)}return r}export async function executeNarrativeProcessors(i,t,o,e){let r=t;for(const n of i)try{r=await n.process(r,o)}catch(s){e.error(`Narrative processor "${n.name}" from "${n.extensionName}" threw: ${s instanceof Error?s.message:String(s)}`)}return r}
